            if direction == "src":
                src = label
                tgt = rel_target
            else:
                src = rel_target
                tgt = label

            formatted.append({
                "label": rel_name,
                "is_relation": True
            })

            formatted.append({
                "relation": rel_name,
                "src": src,
                "target": tgt
            })

        # Transformation des métadonnées en triplés
        for meta_key, meta_value in metas.items():
            if meta_key in ["nom", "type"]:
                continue  # Déjà utilisé
            meta_label = f"{meta_key}:{meta_value}"
            formatted.append({
                "label": meta_label,
                "metas": {
                    "meta_name": meta_key,
                    "meta_value": meta_value
                }
            })
            formatted.append({
                "label": "has_meta",
                "is_relation": True
            })
            formatted.append({
                "relation": "has_meta",
                "src": label,
                "target": meta_label
            })

    return formatted
